from contextlib import asynccontextmanager
import joblib
from fastapi import FastAPI, Request
from pydantic import BaseModel

@asynccontextmanager
async def lifespan(app: FastAPI):
    app.state.model = joblib.load('model.pkl')
    app.state.features = ['Pclass', 'Age', 'Fare']
    app.state.model_version = '1.0.0'
    yield

app = FastAPI(lifespan=lifespan)

class Passenger(BaseModel):
    pclass: int
    age: float
    fare: float

@app.post('/predict')
def predict(passenger: Passenger, request: Request):
    model = request.app.state.model
    X = [[passenger.pclass, passenger.age, passenger.fare]]
    prediction = model.predict(X)[0]
    probability = model.predict_proba(X)[0][1]
    return {
        'survived': bool(prediction),
        'probability': round(float(probability), 3)
    }

@app.get('/model/info')
def model_info(request: Request):
    return {
        'version': request.app.state.model_version,
        'features': request.app.state.features,
        'trained_on': '2024-01-15'
    }
